// MATRIX RAIN
// ════════════════════════════════════════════════
function MatrixRain() {
  const ref = useRef(null);
  useEffect(() => {
    const cv = ref.current, cx = cv.getContext("2d");
    const resize = () => { cv.width = window.innerWidth; cv.height = window.innerHeight; };
    resize();
    const chars = "LIFEINVADER01stalked@dock#efriend$profile%data<>{}[]";
    const fs = 13, cols = Math.floor(cv.width / fs);
    const drops = Array(cols).fill(1);
    const draw = () => {
      cx.fillStyle = "rgba(10,10,15,0.06)";
      cx.fillRect(0, 0, cv.width, cv.height);
      cx.fillStyle = C.termDark;
      cx.font = `${fs}px monospace`;
      for (let i = 0; i < drops.length; i++) {
        cx.fillText(chars[Math.floor(Math.random() * chars.length)], i * fs, drops[i] * fs);
        if (drops[i] * fs > cv.height && Math.random() > 0.975) drops[i] = 0;
        drops[i]++;
      }
    };
    const iv = setInterval(draw, 50);
    window.addEventListener("resize", resize);
    return () => { clearInterval(iv); window.removeEventListener("resize", resize); };
  }, []);
  return <canvas ref={ref} style={{ position: "fixed", inset: 0, zIndex: 0, opacity: 0.35 }} />;
}

