// COUNTDOWN START — 5s timer before hack begins
// ════════════════════════════════════════════════
function CountdownStart({ seconds = 5, color, onDone }) {
  const [count, setCount] = useState(seconds);
  const [progress, setProgress] = useState(100);
  const [ready, setReady] = useState(false);

  useEffect(() => {
    const start = Date.now();
    const total = seconds * 1000;
    const iv = setInterval(() => {
      const elapsed = Date.now() - start;
      const remaining = Math.max(0, total - elapsed);
      const secs = Math.floor(remaining / 1000);
      setCount(secs);
      setProgress((remaining / total) * 100);
      if (remaining <= 0) {
        clearInterval(iv);
        setCount(0);
        setProgress(0);
        setTimeout(() => setReady(true), 150);
      }
    }, 50);
    return () => clearInterval(iv);
  }, []);

  const radius = 58;
  const circ = 2 * Math.PI * radius;
  const dash = circ * (progress / 100);

  if (ready) {
    return (
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "16px", animation: "startAppear 0.4s ease-out" }}>
        <button onClick={onDone} style={{
          position: "relative", width: "160px", height: "160px",
          background: `${C.green}08`, border: `3px solid ${C.green}`,
          borderRadius: "50%", cursor: "pointer", outline: "none", padding: 0,
          boxShadow: `0 0 30px ${C.green}25, inset 0 0 20px ${C.green}10`,
          animation: "startPulse 2s ease-in-out infinite",
          transition: "all 0.2s",
        }}
        onMouseEnter={e => { e.currentTarget.style.background = `${C.green}18`; e.currentTarget.style.transform = "scale(1.08)"; e.currentTarget.style.boxShadow = `0 0 45px ${C.green}40, inset 0 0 30px ${C.green}15`; }}
        onMouseLeave={e => { e.currentTarget.style.background = `${C.green}08`; e.currentTarget.style.transform = "scale(1)"; e.currentTarget.style.boxShadow = `0 0 30px ${C.green}25, inset 0 0 20px ${C.green}10`; }}
        >
          <div style={{
            display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
            height: "100%", gap: "4px",
          }}>
            <div style={{ fontFamily: F.mono, fontSize: "32px", color: C.green, lineHeight: 1 }}>►</div>
            <div style={{ fontFamily: F.mono, fontSize: "18px", fontWeight: "bold", letterSpacing: "4px", color: C.green, textShadow: `0 0 15px ${C.green}` }}>START</div>
          </div>
        </button>
        <div style={{
          fontFamily: F.mono, fontSize: "11px", letterSpacing: "3px",
          color: C.green, opacity: 0.7, textShadow: `0 0 6px ${C.green}`,
        }}>
          CLIQUEZ POUR LANCER
        </div>
        <style>{`
          @keyframes startPulse {
            0%, 100% { box-shadow: 0 0 30px ${C.green}25, inset 0 0 20px ${C.green}10; }
            50% { box-shadow: 0 0 50px ${C.green}40, inset 0 0 35px ${C.green}18; }
          }
          @keyframes startAppear {
            0% { opacity: 0; transform: scale(0.7); }
            100% { opacity: 1; transform: scale(1); }
          }
        `}</style>
      </div>
    );
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "16px" }}>
      <div style={{ position: "relative", width: "150px", height: "150px" }}>
        <svg width="150" height="150" style={{ position: "absolute", top: 0, left: 0 }}>
          <circle cx="75" cy="75" r={radius} fill="none" stroke={`${color}15`} strokeWidth="5" />
          <circle cx="75" cy="75" r={radius} fill="none" stroke={color} strokeWidth="5"
            strokeDasharray={`${dash} ${circ}`}
            strokeLinecap="round" style={{ transition: "stroke-dasharray 0.1s linear", filter: `drop-shadow(0 0 10px ${color})` }}
            transform="rotate(-90 75 75)" />
        </svg>
        <div style={{
          position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center",
          fontFamily: F.mono, fontSize: "56px", fontWeight: "bold",
          color: count <= 2 ? C.red : color,
          textShadow: `0 0 25px ${count <= 2 ? C.red : color}`,
          animation: "countPop 1s ease-in-out infinite",
        }}>
          {count}
        </div>
      </div>
      <div style={{
        fontFamily: F.mono, fontSize: "13px", letterSpacing: "3px",
        color: count <= 2 ? C.red : color, opacity: 0.7,
        textShadow: `0 0 6px ${count <= 2 ? C.red : color}`,
      }}>
        LANCEMENT DANS {count}s
      </div>
      <style>{`
        @keyframes countPop {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.1); }
        }
      `}</style>
    </div>
  );
}

