// ════════════════════════════════════════════════
// LEVEL WIPE TRANSITION — top-down fade out + new level slides in from top
// ════════════════════════════════════════════════
function LevelTransition({ active }) {
  if (!active) return null;
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 9999, pointerEvents: "none" }}>
      {/* Wipe curtain going down */}
      <div style={{
        position: "absolute", inset: 0,
        background: `linear-gradient(180deg, ${C.bg} 0%, ${C.bg}ee 40%, transparent 100%)`,
        animation: "lvlWipeDown 0.45s ease-in-out forwards",
      }} />
      {/* Scanline flash */}
      <div style={{
        position: "absolute", inset: 0,
        background: `repeating-linear-gradient(0deg, transparent, transparent 2px, ${C.terminal}06 2px, ${C.terminal}06 4px)`,
        animation: "lvlWipeDown 0.45s ease-in-out forwards",
      }} />
      <style>{`
        @keyframes lvlWipeDown {
          0% { clip-path: inset(0 0 100% 0); opacity: 1; }
          50% { clip-path: inset(0 0 0% 0); opacity: 0.9; }
          100% { clip-path: inset(100% 0 0 0); opacity: 0; }
        }
      `}</style>
    </div>
  );
}

function Thermite({ onComplete }) {
  const [level, setLevel] = useState(0);
  const [phase, setPhase] = useState("show");
  const [targets, setTargets] = useState([]);
  const [clicked, setClicked] = useState([]);
  const [wrongCells, setWrongCells] = useState([]);
  const [showCountdown, setShowCountdown] = useState(0);
  const [showError, setShowError] = useState(false);
  const [errorsLeft, setErrorsLeft] = useState(3);
  const [lvlWipe, setLvlWipe] = useState(false);
  const MAX_ERR = 3;
  const countdownRef = useRef(null);

  const startLevel = useCallback((lvl) => {
    const { size, count, showTime } = THERM_LEVELS[lvl];
    const t = new Set();
    while (t.size < count) t.add(Math.floor(Math.random() * size * size));
    setTargets([...t]);
    setClicked([]);
    setWrongCells([]);
    setErrorsLeft(MAX_ERR);
    setPhase("show");
    setShowCountdown(showTime / 1000);
    clearInterval(countdownRef.current);
    countdownRef.current = setInterval(() => {
      setShowCountdown(prev => {
        if (prev <= 1) { clearInterval(countdownRef.current); return 0; }
        return prev - 1;
      });
    }, 1000);
    setTimeout(() => { clearInterval(countdownRef.current); setPhase("play"); }, showTime);
  }, []);

  useEffect(() => { startLevel(0); return () => clearInterval(countdownRef.current); }, [startLevel]);

  const click = (i) => {
    if (phase !== "play" || clicked.includes(i) || wrongCells.includes(i)) return;
    const { count } = THERM_LEVELS[level];
    if (!targets.includes(i)) {
      const ne = errorsLeft - 1;
      setErrorsLeft(ne);
      setWrongCells(prev => [...prev, i]);
      if (ne <= 0) { setShowError(true); setPhase("fail"); }
      return;
    }
    const nc = [...clicked, i];
    setClicked(nc);
    if (nc.filter(c => targets.includes(c)).length === count) {
      if (level + 1 >= THERM_LEVELS.length) {
        setPhase("success");
        setTimeout(onComplete, 1500);
      } else {
        setPhase("levelwin");
        setTimeout(() => {
          setLvlWipe(true);
          setTimeout(() => {
            const next = level + 1;
            setLevel(next);
            startLevel(next);
            setTimeout(() => setLvlWipe(false), 100);
          }, 350);
        }, 1200);
      }
    }
  };

  const { size } = THERM_LEVELS[level];
  const cellSize = size <= 4 ? 60 : size <= 6 ? 46 : 38;

  const color = (i) => {
    if (phase === "show" && targets.includes(i)) return C.terminal;
    if ((phase === "success" || phase === "levelwin") && targets.includes(i)) return C.green;
    if (wrongCells.includes(i)) return C.red;
    if (clicked.includes(i)) return C.cyan;
    return "transparent";
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: "80vh", position: "relative", zIndex: 1 }}>
      <LevelTransition active={lvlWipe} />
      <div key={level} style={{ animation: "lvlSlideIn 0.4s ease-out", display: "flex", flexDirection: "column", alignItems: "center" }}>
      <HackHeader title="NEURAL BRUTE" sub="Memorise les cases puis reproduis le schema" color={C.terminal} step="2/4" onSkip={onComplete} description="Une grille affiche des cases illuminees pendant quelques secondes. 3 niveaux de difficulte croissante (4x4, 5x5, 6x6). Reproduis le schema de memoire." example="Les cases [1,3] et [2,1] s'allument pendant 5s. Apres disparition, clique sur ces memes cases pour valider." />

      <div style={{ fontFamily: F.mono, fontSize: "13px", color: C.yellow, marginBottom: "10px", textShadow: `0 0 8px ${C.yellow}` }}>
        NIVEAU {level + 1}/3 — {size}x{size}
      </div>

      {phase === "show" && (
        <div style={{ fontFamily: F.mono, fontSize: "13px", color: C.yellow, marginBottom: "15px", textShadow: `0 0 10px ${C.yellow}`, display: "flex", alignItems: "center", gap: "12px" }}>
          <span style={{ animation: "softFade 1.2s ease-in-out infinite" }}>⚠ MEMORISE...</span>
          <span style={{ fontSize: "18px", fontWeight: "bold", color: showCountdown <= 3 ? C.red : C.yellow, textShadow: `0 0 12px ${showCountdown <= 3 ? C.red : C.yellow}` }}>{showCountdown}s</span>
        </div>
      )}
      {phase === "play" && (
        <div style={{ fontFamily: F.mono, fontSize: "13px", color: C.cyan, marginBottom: "15px", textShadow: `0 0 8px ${C.cyan}`, display: "flex", alignItems: "center", gap: "20px" }}>
          <span>► REPRODUIS LE SCHEMA</span>
          <IntegrityBar current={errorsLeft} max={MAX_ERR} />
        </div>
      )}

      <div style={{
        display: "inline-grid",
        gridTemplateColumns: `repeat(${size}, 1fr)`,
        gap: size <= 4 ? "6px" : "5px",
        padding: "12px",
        background: "rgba(0,255,65,0.03)",
        borderRadius: "8px",
        border: `1px solid #3a3a4a`,
        boxShadow: `0 0 20px rgba(100,100,140,0.08)`,
      }}>
        {Array.from({ length: size * size }).map((_, i) => (
          <div key={i} onClick={() => click(i)} style={{
            width: `${cellSize}px`, height: `${cellSize}px`,
            background: color(i),
            border: `2px solid ${color(i) !== "transparent" ? color(i) : "#3a3a4a"}`,
            borderRadius: "4px",
            cursor: phase === "play" ? "pointer" : "default",
            transition: "all 0.15s",
            boxShadow: color(i) !== "transparent" ? `0 0 12px ${color(i)}50` : `inset 0 0 6px rgba(255,255,255,0.03), 0 0 4px rgba(100,100,140,0.15)`,
          }} />
        ))}
      </div>

      {phase === "levelwin" && (
        <div style={{ fontFamily: F.mono, fontSize: "16px", color: C.green, marginTop: "18px", textShadow: `0 0 12px ${C.green}` }}>
          ✓ NIVEAU {level + 1} COMPLETE
        </div>
      )}
      {phase === "success" && <StatusMsg ok text="SYSTEME PIRATE" />}
      </div>
      <ErrorOverlay visible={showError} onDone={() => { setShowError(false); setLvlWipe(false); setLevel(0); startLevel(0); }} />
      <style>{`
        @keyframes softFade { 0%,100%{opacity:1} 50%{opacity:0.35} }
        @keyframes lvlSlideIn { 0% { opacity:0; transform:translateY(-30px); } 100% { opacity:1; transform:translateY(0); } }
      `}</style>
    </div>
  );
}

// ════════════════════════════════════════════════
// CYPHER LOCK — NoPixel Fleeca-style
// Large shapes with numbers inside, confusing text labels
// ════════════════════════════════════════════════
const CL_SHAPES_LIST = ["CARRE","RECTANGLE","CERCLE","TRIANGLE"];
const CL_COLORS_FR = ["BLEU","VERT","ROUGE","ORANGE","JAUNE","VIOLET","NOIR","BLANC","ROSE","CYAN","GRIS","MARRON"];
const CL_HEX = {BLEU:"#2195ee",VERT:"#4cae4f",ROUGE:"#d32f2f",ORANGE:"#fd9802",JAUNE:"#fceb3d",VIOLET:"#9926ac",NOIR:"#1a1a1a",BLANC:"#f0f0f0",ROSE:"#ff69b4",CYAN:"#00e5ff",GRIS:"#888888",MARRON:"#8B4513"};

const CL_TYPES = [
  {type:"bg",text:"couleur de fond de la carte"},
  {type:"numColor",text:"couleur du chiffre"},
  {type:"shape",text:"type de forme"},
  {type:"shapeColor",text:"couleur de la forme"},
  {type:"textColor",text:"mot du haut (texte écrit)"},
  {type:"textColorBg",text:"couleur du mot du haut"},
  {type:"textShape",text:"mot du bas (texte écrit)"},
  {type:"textShapeBg",text:"couleur du mot du bas"},
];

function shuffle(a) { const b = [...a]; for (let i = b.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [b[i], b[j]] = [b[j], b[i]]; } return b; }
const clRand = (arr) => arr[Math.floor(Math.random() * arr.length)];

function createCLGame() {
  let realNums = shuffle([1,2,3,4]);
  let impostorNums = shuffle([1,2,3,4]);
  const shuffledShapes = shuffle([...CL_SHAPES_LIST]);
  const shuffledTextShapes = shuffle([...CL_SHAPES_LIST]);
  const groups = [];
  for (let i = 0; i < 4; i++) {
    const bgc = shuffle([...CL_COLORS_FR]);
    const txc = shuffle([...CL_COLORS_FR]);
    groups.push({
      realNum: realNums[i],
      impostorNum: impostorNums[i],
      bg: bgc[0],
      numColor: clRand(CL_COLORS_FR),
      shape: shuffledShapes[i],
      shapeColor: bgc[1],
      textColor: clRand(CL_COLORS_FR),
      textColorBg: txc[0],
      textShape: shuffledTextShapes[i],
      textShapeBg: txc[1],
    });
  }
  const qNums = shuffle([0,1,2,3]);
  const types = shuffle([...CL_TYPES]);
  const getSol = (g, t) => {
    const m = {bg:g.bg,numColor:g.numColor,shape:g.shape,shapeColor:g.shapeColor,textColor:g.textColor,textColorBg:g.textColorBg,textShape:g.textShape,textShapeBg:g.textShapeBg};
    return m[t.type] || "";
  };
  const sol1 = getSol(groups[qNums[0]], types[0]);
  const sol2 = getSol(groups[qNums[1]], types[1]);
  return {
    realNums, impostorNums, groups,
    quiz1: {pos:qNums[0], type:types[0], solution:sol1},
    quiz2: {pos:qNums[1], type:types[1], solution:sol2},
    solution: sol1.toLowerCase()+" "+sol2.toLowerCase(),
  };
}

// Shape renderer for Cypher Lock cards
function CLShape({ type, color, size }) {
  const hex = CL_HEX[color] || "#888";
  const s = size;
  const m = 20;
  if (type === "CARRE") return <div style={{width:s-m*2,height:s-m*2,margin:m,background:hex,border:"2px solid #000",borderRadius:"2px"}} />;
  if (type === "RECTANGLE") return <div style={{width:s-m*2,height:(s-m*2)*0.6,margin:`${m+s*0.2}px ${m}px`,background:hex,border:"2px solid #000",borderRadius:"2px"}} />;
  if (type === "CERCLE") return <div style={{width:s-m*2,height:s-m*2,margin:m,background:hex,border:"2px solid #000",borderRadius:"50%"}} />;
  if (type === "TRIANGLE") return (
    <div style={{width:0,height:0,margin:`${m}px auto`,borderLeft:`${(s-m*2)/2}px solid transparent`,borderRight:`${(s-m*2)/2}px solid transparent`,borderBottom:`${s-m*2}px solid ${hex}`}} />
  );
  if (type === "LOSANGE") return (
    <div style={{width:s-m*2,height:s-m*2,margin:m,background:hex,border:"2px solid #000",transform:"rotate(45deg)",borderRadius:"3px",transformOrigin:"center"}} />
  );
  if (type === "HEXAGONE") return (
    <div style={{width:s-m*2,height:s-m*2,margin:m,background:hex,border:"2px solid #000",borderRadius:"25%",clipPath:"polygon(50% 0%, 100% 25%, 100% 75%, 50% 100%, 0% 75%, 0% 25%)"}} />
  );
  return null;
}

function Fleeca({ onComplete }) {
  const [phase, setPhase] = useState("memorize");
  const [data, setData] = useState(null);
  const [displayOrder, setDisplayOrder] = useState([0,1,2,3]);
  const [timeLeft, setTimeLeft] = useState(15);
  const [showError, setShowError] = useState(false);
  const [answer, setAnswer] = useState("");
  const [answerState, setAnswerState] = useState("");
  const timerRef = useRef(null);
  const inputRef = useRef(null);
  const TIMER = 15;

  const init = useCallback(() => {
    const d = createCLGame();
    setData(d);
    setDisplayOrder(shuffle([0,1,2,3]));
    setAnswer("");
    setAnswerState("");
    setTimeLeft(TIMER);
    setPhase("memorize");
    // Phase 1: show real numbers for 4s, then shrink, then show puzzle
    setTimeout(() => setPhase("shrink"), 4000);
    setTimeout(() => {
      setPhase("puzzle");
      const start = Date.now();
      timerRef.current = setInterval(() => {
        const rem = Math.max(0, TIMER - (Date.now() - start) / 1000);
        setTimeLeft(rem);
        if (rem <= 0) { clearInterval(timerRef.current); setShowError(true); setPhase("fail"); }
      }, 50);
    }, 6000);
  }, []);

  useEffect(() => { init(); return () => clearInterval(timerRef.current); }, [init]);
  useEffect(() => { if (phase === "puzzle" && inputRef.current) inputRef.current.focus(); }, [phase]);

  const handleSubmit = () => {
    if (phase !== "puzzle") return;
    clearInterval(timerRef.current);
    if (answer.toLowerCase().trim() === data.solution) {
      setAnswerState("right");
      setPhase("success");
      setTimeout(onComplete, 1500);
    } else {
      setAnswerState("wrong");
      setShowError(true);
      setPhase("fail");
    }
  };

  const pct = (timeLeft / TIMER) * 100;
  const timerColor = timeLeft <= 2 ? C.red : timeLeft <= 4 ? C.yellow : C.terminal;
  const cardSize = 200;

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: "80vh", position: "relative", zIndex: 1 }}>
      <HackHeader title="CYPHER LOCK" sub="Memorise les numeros, puis reponds a la question" color={C.cyan} step="4/4" onSkip={onComplete} description="4 cartes affichent un numero chacune (1 a 4). Les cartes se melangent et se remplissent de formes/textes. Reponds a la question avant la fin du chrono." example="Question: couleur du chiffre carte #2 + forme carte #3. Si chiffre 2 est bleu et forme est carre → tape 'bleu carre'." />

      {/* 4 Cards */}
      {data && (phase === "memorize" || phase === "shrink" || phase === "puzzle") && (
        <div style={{ display: "flex", gap: "18px", flexWrap: "wrap", justifyContent: "center", marginBottom: "20px" }}>
          {displayOrder.map((gi, si) => {
            const g = data.groups[gi];
            const bgHex = CL_HEX[g.bg] || "#333";
            return (
              <div key={si} style={{
                width: cardSize, height: cardSize,
                background: bgHex,
                border: "2px solid #000",
                borderRadius: "4px",
                position: "relative",
                overflow: "hidden",
              }}>
                {/* Phase memorize/shrink: show real number */}
                {(phase === "memorize" || phase === "shrink") && (
                  <div style={{
                    position: "absolute", inset: 0,
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontFamily: F.mono, fontSize: phase === "shrink" ? "0px" : "140px",
                    fontWeight: 900, color: "#fff",
                    transition: "font-size 1.8s ease-in-out",
                    zIndex: 10, background: "#21262d",
                  }}>{g.realNum}</div>
                )}
                {/* Phase puzzle: show shape + confusing text */}
                {phase === "puzzle" && (
                  <>
                    <div style={{ position: "absolute", inset: 0 }}>
                      <CLShape type={g.shape} color={g.shapeColor} size={cardSize} />
                    </div>
                    {/* Text color label (top) */}
                    <div style={{
                      position: "absolute", top: "55px", width: "100%", textAlign: "center",
                      fontFamily: "'Arial Black', sans-serif", fontSize: "22px", fontWeight: 900,
                      textTransform: "uppercase", color: CL_HEX[g.textColorBg] || "#fff",
                      WebkitTextStroke: "1px rgba(0,0,0,0.5)", zIndex: 5,
                      textShadow: "0 2px 4px rgba(0,0,0,0.5)", letterSpacing: "1px",
                    }}>{g.textColor}</div>
                    {/* Text shape label (bottom) */}
                    <div style={{
                      position: "absolute", top: "120px", width: "100%", textAlign: "center",
                      fontFamily: "'Arial Black', sans-serif", fontSize: "22px", fontWeight: 900,
                      textTransform: "uppercase", color: CL_HEX[g.textShapeBg] || "#fff",
                      WebkitTextStroke: "1px rgba(0,0,0,0.5)", zIndex: 5,
                      textShadow: "0 2px 4px rgba(0,0,0,0.5)", letterSpacing: "1px",
                    }}>{g.textShape}</div>
                    {/* Impostor number */}
                    <div style={{
                      position: "absolute", top: "70px", width: "100%", textAlign: "center",
                      fontFamily: F.mono, fontSize: "60px", fontWeight: 900,
                      color: CL_HEX[g.numColor] || "#fff",
                      WebkitTextStroke: "1px rgba(0,0,0,0.4)", zIndex: 3,
                    }}>{g.impostorNum}</div>
                  </>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Memorize message */}
      {phase === "memorize" && (
        <div style={{ fontFamily: F.mono, fontSize: "15px", color: C.yellow, animation: "softFade 1.4s ease-in-out infinite", textShadow: `0 0 10px ${C.yellow}` }}>
          ⚠ MEMORISE LES NUMEROS
        </div>
      )}

      {/* Timer + Question + Answer */}
      {phase === "puzzle" && data && (
        <>
          <div style={{ width: "min(92vw, 600px)", marginBottom: "8px" }}>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "3px" }}>
              <span style={{ fontFamily: F.mono, fontSize: "13px", color: timerColor, textShadow: `0 0 8px ${timerColor}`, animation: timeLeft < 2 ? "softFade 0.4s infinite" : "none" }}>
                ⏱ {timeLeft.toFixed(1)}s
              </span>
              <span style={{ fontFamily: F.mono, fontSize: "13px", color: C.termDim }}>{TIMER}s</span>
            </div>
            <div style={{ height: "6px", background: C.termDark, borderRadius: "3px", overflow: "hidden" }}>
              <div style={{ height: "100%", width: `${pct}%`, background: timerColor, borderRadius: "3px", boxShadow: `0 0 10px ${timerColor}`, transition: "background 0.3s" }} />
            </div>
          </div>
          <div style={{ fontFamily: F.mono, fontSize: "14px", color: C.white, marginBottom: "16px", textAlign: "center", lineHeight: 1.8 }}>
            Carte <span style={{ color: C.cyan, fontWeight: "bold" }}>#{data.realNums[data.quiz1.pos]}</span> → <span style={{ color: C.yellow }}>{data.quiz1.type.text}</span>
            <br/>
            Carte <span style={{ color: C.cyan, fontWeight: "bold" }}>#{data.realNums[data.quiz2.pos]}</span> → <span style={{ color: C.yellow }}>{data.quiz2.type.text}</span>
            <br/>
            <span style={{ fontSize: "12px", color: C.termDim }}>(sépare les 2 réponses par un espace)</span>
          </div>
          <div style={{ display: "flex", gap: "0", border: `1px solid ${answerState === "wrong" ? C.red : answerState === "right" ? C.terminal : C.cyan}`, borderRadius: "4px", overflow: "hidden", transition: "border-color 0.3s", boxShadow: `0 0 15px ${C.cyan}20` }}>
            <div style={{ padding: "10px 14px", fontFamily: F.mono, fontSize: "13px", color: C.termDim, background: `${C.cyan}08`, borderRight: `1px solid ${C.termDark}` }}>
              root@vault:~$
            </div>
            <input
              ref={inputRef}
              type="text" value={answer}
              onChange={e => setAnswer(e.target.value)}
              onKeyDown={e => e.key === "Enter" && handleSubmit()}
              placeholder="ex: bleu carre"
              style={{ background: "transparent", border: "none", outline: "none", color: C.cyan, fontFamily: F.mono, fontSize: "15px", padding: "10px 16px", width: "240px", letterSpacing: "1px", textShadow: `0 0 5px ${C.cyan}` }}
            />
            <button onClick={handleSubmit} style={{ background: `${C.cyan}15`, border: "none", borderLeft: `1px solid ${C.termDark}`, color: C.cyan, fontFamily: F.mono, fontSize: "13px", padding: "10px 16px", cursor: "pointer" }}>
              ENTRER
            </button>
          </div>
        </>
      )}

      {phase === "success" && <StatusMsg ok text="COFFRE OUVERT" />}
      <ErrorOverlay visible={showError} onDone={() => { setShowError(false); init(); }} />
      <style>{`@keyframes softFade { 0%,100%{opacity:1} 50%{opacity:0.35} }`}</style>
    </div>
  );
}

// ════════════════════════════════════════════════
// GRID SCANNER — scrolling character grid, 3 rounds
// ════════════════════════════════════════════════
const CHAR_POOL = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";

const ROUNDS = [
  { size: 6, targetLen: 5, time: 10 },
  { size: 8, targetLen: 7, time: 15 },
  { size: 10, targetLen: 9, time: 20 },
];

function HackingDevice({ onComplete }) {
  const [round, setRound] = useState(0);
  const [phase, setPhase] = useState("play");
  const [target, setTarget] = useState([]);
  const [grid, setGrid] = useState([]);
  const [hoverIdx, setHoverIdx] = useState(-1);
  const [inputMode, setInputMode] = useState("mouse"); // "mouse" | "keyboard"
  const [showError, setShowError] = useState(false);
  const [errorsLeft, setErrorsLeft] = useState(3);
  const [countdown, setCountdown] = useState(10);
  const [lvlWipe, setLvlWipe] = useState(false);
  const scrollRef = useRef(null);
  const timerRef = useRef(null);
  const gridRef = useRef([]);
  const targetPosRef = useRef([]);
  const containerRef = useRef(null);
  const MAX_ERR = 3;

  const rc = () => CHAR_POOL[Math.floor(Math.random() * CHAR_POOL.length)];

  const shiftGrid = (currentGrid, s) => {
    const total = s * s;
    const newGrid = new Array(total);
    for (let i = 0; i < total; i++) {
      // Each cell moves one position left; col 0 wraps to col s-1 of row above; row 0 col 0 wraps to row s-1 col s-1
      const row = Math.floor(i / s);
      const col = i % s;
      let srcRow, srcCol;
      if (col === s - 1) {
        srcRow = row === s - 1 ? 0 : row + 1;
        srcCol = 0;
      } else {
        srcRow = row;
        srcCol = col + 1;
      }
      newGrid[i] = currentGrid[srcRow * s + srcCol];
    }
    return newGrid;
  };

  const initRound = useCallback((r) => {
    const { size, targetLen, time } = ROUNDS[r];
    const total = size * size;

    const tgt = [];
    for (let i = 0; i < targetLen; i++) tgt.push(rc());

    const g = [];
    for (let i = 0; i < total; i++) g.push(rc());

    // Place target contiguously in a row (no wrapping for simplicity)
    const row = Math.floor(Math.random() * size);
    const maxCol = size - targetLen;
    const startCol = Math.floor(Math.random() * (maxCol + 1));
    const positions = [];
    tgt.forEach((ch, i) => {
      const idx = row * size + startCol + i;
      g[idx] = ch;
      positions.push(idx);
    });

    setTarget(tgt);
    setGrid(g);
    gridRef.current = [...g];
    targetPosRef.current = positions;
    setHoverIdx(-1);
    setErrorsLeft(MAX_ERR);
    setCountdown(time);
    setPhase("play");

    if (scrollRef.current) clearInterval(scrollRef.current);
    if (timerRef.current) clearInterval(timerRef.current);

    // Countdown timer
    timerRef.current = setInterval(() => {
      setCountdown(prev => {
        if (prev <= 1) {
          clearInterval(timerRef.current);
          clearInterval(scrollRef.current);
          setShowError(true);
          setPhase("fail");
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    let cur = [...g];
    let curPositions = [...positions];
    scrollRef.current = setInterval(() => {
      const s = ROUNDS[r].size;
      cur = shiftGrid(cur, s);
      curPositions = curPositions.map(p => {
        const row = Math.floor(p / s);
        const col = p % s;
        let newCol = col - 1;
        let newRow = row;
        if (newCol < 0) {
          newCol = s - 1;
          newRow = row - 1;
          if (newRow < 0) newRow = s - 1;
        }
        return newRow * s + newCol;
      });
      gridRef.current = cur;
      targetPosRef.current = curPositions;
      setGrid([...cur]);
    }, 1200);
  }, []);

  useEffect(() => {
    initRound(0);
    return () => { clearInterval(scrollRef.current); clearInterval(timerRef.current); };
  }, [initRound]);

  // Focus container for keyboard events
  useEffect(() => {
    if (containerRef.current) containerRef.current.focus();
  }, [phase, round]);

  const handleClickRef = useRef(null);

  // Keyboard navigation: arrows move hoverIdx, Enter validates
  const handleKeyDown = useCallback((e) => {
    if (phase !== "play") return;
    const { size } = ROUNDS[round];
    const total = size * size;
    if (["ArrowUp","ArrowDown","ArrowLeft","ArrowRight"].includes(e.key)) {
      e.preventDefault();
      setInputMode("keyboard");
      setHoverIdx(prev => {
        let idx = prev < 0 ? 0 : prev;
        if (e.key === "ArrowLeft") idx = ((idx - 1) % total + total) % total;
        if (e.key === "ArrowRight") idx = (idx + 1) % total;
        if (e.key === "ArrowUp") idx = ((idx - size) % total + total) % total;
        if (e.key === "ArrowDown") idx = (idx + size) % total;
        return idx;
      });
    }
    if (e.key === "Enter") {
      e.preventDefault();
      if (handleClickRef.current) handleClickRef.current();
    }
  }, [phase, round]);

  // Get highlighted cells: mouse → hovered cell is leftmost; keyboard → centered on hoverIdx
  const getHighlightedCells = (idx) => {
    if (idx < 0 || phase !== "play") return [];
    const { size, targetLen } = ROUNDS[round];
    const total = size * size;
    const cells = [];
    if (inputMode === "mouse") {
      // Mouse: hovered cell is the leftmost
      for (let i = 0; i < targetLen; i++) {
        cells.push(((idx + i) % total + total) % total);
      }
    } else {
      // Keyboard: centered on hoverIdx
      const half = Math.floor(targetLen / 2);
      for (let i = -half; i < targetLen - half; i++) {
        cells.push(((idx + i) % total + total) % total);
      }
    }
    return cells;
  };

  const highlightedCells = getHighlightedCells(hoverIdx);

  const handleClick = () => {
    if (phase !== "play" || highlightedCells.length === 0) return;

    clearInterval(scrollRef.current);
    clearInterval(timerRef.current);

    // Check if highlighted cells match the target positions exactly
    const sortedHl = [...highlightedCells].sort((a, b) => a - b);
    const sortedTp = [...targetPosRef.current].sort((a, b) => a - b);
    const match = sortedHl.length === sortedTp.length && sortedHl.every((v, i) => v === sortedTp[i]);

    if (match) {
      setPhase("roundwin");
      setTimeout(() => {
        const nextRound = round + 1;
        if (nextRound >= ROUNDS.length) {
          setPhase("success");
          setTimeout(onComplete, 1500);
        } else {
          setLvlWipe(true);
          setTimeout(() => {
            setRound(nextRound);
            initRound(nextRound);
            setTimeout(() => setLvlWipe(false), 100);
          }, 350);
        }
      }, 1200);
    } else {
      const ne = errorsLeft - 1;
      setErrorsLeft(ne);
      if (ne <= 0) {
        setShowError(true);
        setPhase("fail");
      } else {
        // Resume scrolling and timer
        timerRef.current = setInterval(() => {
          setCountdown(prev => {
            if (prev <= 1) {
              clearInterval(timerRef.current);
              clearInterval(scrollRef.current);
              setShowError(true);
              setPhase("fail");
              return 0;
            }
            return prev - 1;
          });
        }, 1000);
        let cur = [...gridRef.current];
        let curPositions = [...targetPosRef.current];
        scrollRef.current = setInterval(() => {
          const s = ROUNDS[round].size;
          cur = shiftGrid(cur, s);
          curPositions = curPositions.map(p => {
            const row = Math.floor(p / s);
            const col = p % s;
            let newCol = col - 1;
            let newRow = row;
            if (newCol < 0) { newCol = s - 1; newRow = row - 1; if (newRow < 0) newRow = s - 1; }
            return newRow * s + newCol;
          });
          gridRef.current = cur;
          targetPosRef.current = curPositions;
          setGrid([...cur]);
        }, 1200);
      }
    }
  };
  handleClickRef.current = handleClick;

  const restart = () => {
    setRound(0);
    initRound(0);
  };

  const { size, targetLen } = ROUNDS[round] || ROUNDS[0];
  const cellSize = size <= 6 ? 58 : size <= 8 ? 48 : 40;
  const fontSize = size <= 6 ? 24 : size <= 8 ? 20 : 16;

  return (
    <div ref={containerRef} tabIndex={0} onKeyDown={handleKeyDown} style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: "80vh", position: "relative", zIndex: 1, outline: "none" }}>
      <LevelTransition active={lvlWipe} />
      <div key={round} style={{ animation: "lvlSlideIn 0.4s ease-out", display: "flex", flexDirection: "column", alignItems: "center", width: "100%" }}>
      <HackHeader title="GRID SCANNER" sub="Survole ou utilise les fleches, valide avec clic ou Entree" color={C.yellow} step="3/4" onSkip={onComplete} description="Une grille de caracteres defilants apparait avec une sequence CIBLE en haut. Survole les cases ou utilise les fleches pour surligner. 3 rounds de difficulte croissante." example="Cible: A B 7 K → trouve cette suite exacte dans la grille et valide avec clic ou Entree." />

      <div style={{ fontFamily: F.mono, fontSize: "13px", color: C.yellow, marginBottom: "10px", textShadow: `0 0 8px ${C.yellow}` }}>
        ROUND {round + 1}/3 — {size}x{size}
      </div>

      {phase === "play" && (
        <div style={{ fontFamily: F.mono, fontSize: "13px", marginBottom: "12px", display: "flex", alignItems: "center", gap: "20px", flexWrap: "wrap", justifyContent: "center" }}>
          <span style={{ color: countdown <= 5 ? C.red : C.yellow, textShadow: `0 0 8px ${countdown <= 5 ? C.red : C.yellow}` }}>
            TEMPS: {countdown}s
          </span>
          <span style={{ color: C.termDim }}>CIBLE: {targetLen} CARACTERES</span>
          <IntegrityBar current={errorsLeft} max={MAX_ERR} />
        </div>
      )}

      {/* Target display */}
      <div style={{
        display: "flex", gap: "6px", marginBottom: "16px", padding: "10px 18px",
        background: `${C.yellow}08`, borderRadius: "8px", border: `1px solid ${C.yellow}40`,
        boxShadow: `0 0 12px ${C.yellow}12`, flexWrap: "wrap", justifyContent: "center",
      }}>
        <span style={{ fontFamily: F.mono, fontSize: "12px", color: C.termDim, alignSelf: "center", marginRight: "8px" }}>CIBLE:</span>
        {target.map((ch, i) => (
          <div key={i} style={{
            width: "32px", height: "32px",
            display: "flex", alignItems: "center", justifyContent: "center",
            fontFamily: F.mono, fontSize: "18px", fontWeight: "bold",
            border: `2px solid ${C.yellow}`,
            borderRadius: "4px",
            color: C.yellow,
            background: `${C.yellow}10`,
            textShadow: `0 0 8px ${C.yellow}`,
          }}>{ch}</div>
        ))}
      </div>

      {/* Grid */}
      <div
        onClick={handleClick}
        onMouseLeave={() => setHoverIdx(-1)}
        style={{
          display: "inline-grid",
          gridTemplateColumns: `repeat(${size}, 1fr)`,
          gap: size <= 5 ? "4px" : size <= 10 ? "3px" : "2px",
          padding: "10px",
          background: `${C.yellow}03`,
          borderRadius: "8px",
          border: `1px solid ${C.yellow}20`,
          cursor: phase === "play" ? "pointer" : "default",
        }}
      >
        {grid.map((ch, i) => {
          const isHl = highlightedCells.includes(i);
          return (
            <div
              key={i}
              onMouseEnter={() => { if (phase === "play") { setInputMode("mouse"); setHoverIdx(i); } }}
              style={{
                width: `${cellSize}px`, height: `${cellSize}px`,
                display: "flex", alignItems: "center", justifyContent: "center",
                fontFamily: F.mono, fontSize: `${fontSize}px`, fontWeight: "bold",
                background: isHl ? `${C.cyan}25` : `${C.yellow}04`,
                border: `1px solid ${isHl ? C.cyan : `${C.yellow}15`}`,
                borderRadius: "3px",
                color: isHl ? C.cyan : `${C.white}bb`,
                transition: "background 0.08s, border-color 0.08s, color 0.08s",
                textShadow: isHl ? `0 0 6px ${C.cyan}` : "none",
                pointerEvents: "auto",
              }}
            >{ch}</div>
          );
        })}
      </div>

      {phase === "roundwin" && (
        <div style={{ fontFamily: F.mono, fontSize: "16px", color: C.green, marginTop: "18px", textShadow: `0 0 12px ${C.green}` }}>
          ✓ ROUND {round + 1} COMPLETE
        </div>
      )}
      {phase === "success" && <StatusMsg ok text="SYSTEME INFILTRE" />}
      </div>
      <ErrorOverlay visible={showError} onDone={() => { setShowError(false); setLvlWipe(false); restart(); }} />
      <style>{`@keyframes lvlSlideIn { 0% { opacity:0; transform:translateY(-30px); } 100% { opacity:1; transform:translateY(0); } }`}</style>
    </div>
  );
}

// ════════════════════════════════════════════════
// TRACEUR GPS — word memory
// ════════════════════════════════════════════════
const WORDS_R1 = [
  "Hacker","Cybersecurite","Reseau","Serveur","Client","Protocole","TCP","IP",
  "DNS","Firewall","Malware","Virus","Trojan","Phishing","Exploit","Vulnerabilite",
  "Cryptographie","Chiffrement","Dechiffrement","Cle publique",
];
const WORDS_R2 = [
  ...WORDS_R1,
  "Cle privee","Authentification","Autorisation","Backdoor","Rootkit","Botnet",
  "Packet","Sniffing","Spoofing","Injection","SQL","Script","Terminal","Shell",
  "Linux","Kernel","Virtualisation","Machine virtuelle","Cloud","Data center",
];
const WORDS_R3 = [
  ...WORDS_R2,
  "API","Token","Session","Cookie","Proxy","VPN","Tor","Anonymat","Securite",
  "Audit","Pentest","Scan","Port","Socket","Bande passante","Latence","Upload",
  "Download","Infrastructure","Architecture",
];
const ROUND_POOLS = [WORDS_R1, WORDS_R2, WORDS_R3];

function VarSim({ onComplete }) {
  const ROUNDS_TOTAL = 3;
  const WORDS_PER_ROUND = 20;
  const MAX_ERR = 3;

  const [round, setRound] = useState(1);
  const [phase, setPhase] = useState("play");
  const [wordSeq, setWordSeq] = useState([]);
  const [idx, setIdx] = useState(0);
  const [seenEver, setSeenEver] = useState(new Set());
  const [seenThisSeq, setSeenThisSeq] = useState(new Set());
  const [errors, setErrors] = useState(0);
  const [feedback, setFeedback] = useState(null);
  const [showError, setShowError] = useState(false);
  const [lvlWipe, setLvlWipe] = useState(false);
  const usedWordsRef = useRef([]);

  const buildSeq = (roundNum, oldWords) => {
    const pool = ROUND_POOLS[Math.min(roundNum - 1, ROUND_POOLS.length - 1)];
    const shuffled = [...pool].sort(() => Math.random() - 0.5);
    const newUnique = shuffled.filter(w => !oldWords.includes(w)).slice(0, 10);
    const allAvailable = [...oldWords, ...newUnique];
    usedWordsRef.current = [...new Set(allAvailable)];

    const seq = [];
    const introduced = new Set();
    for (let i = 0; i < WORDS_PER_ROUND; i++) {
      const lastWord = seq.length > 0 ? seq[seq.length - 1] : null;
      let word = null;
      let attempts = 0;
      while (!word || (word === lastWord && attempts < 20)) {
        attempts++;
        const canRepeatOld = oldWords.length > 0 && i > 2 && Math.random() > 0.6;
        const canRepeatNew = introduced.size > 3 && Math.random() > 0.5;
        if (canRepeatOld) {
          const arr = [...oldWords];
          word = arr[Math.floor(Math.random() * arr.length)];
        } else if (canRepeatNew) {
          const arr = [...introduced];
          word = arr[Math.floor(Math.random() * arr.length)];
        } else {
          word = newUnique[i % newUnique.length];
          break;
        }
      }
      seq.push(word);
      introduced.add(word);
    }
    return seq;
  };

  useEffect(() => { setWordSeq(buildSeq(1, [])); }, []);

  const initRound = (r) => {
    const oldWords = [...seenEver];
    const seq = buildSeq(r, oldWords);
    setWordSeq(seq);
    setIdx(0);
    setSeenThisSeq(new Set());
    setErrors(0);
    setFeedback(null);
    setPhase("play");
    setRound(r);
  };

  const init = () => {
    setSeenEver(new Set());
    usedWordsRef.current = [];
    const seq = buildSeq(1, []);
    setWordSeq(seq);
    setIdx(0);
    setSeenThisSeq(new Set());
    setErrors(0);
    setFeedback(null);
    setPhase("play");
    setRound(1);
  };

  const answer = (isNew) => {
    if (phase !== "play" || !wordSeq[idx]) return;
    const word = wordSeq[idx];
    // A word is "already seen" if it appeared earlier in this sequence OR in any previous round
    const alreadySeen = seenThisSeq.has(word) || seenEver.has(word);
    const correct = isNew ? !alreadySeen : alreadySeen;

    if (correct) {
      setFeedback("ok");
    } else {
      setFeedback("no");
      const ne = errors + 1;
      setErrors(ne);
      if (ne >= MAX_ERR) { setShowError(true); setPhase("fail"); return; }
    }

    // Track this word as seen in the current sequence
    const ns = new Set(seenThisSeq);
    ns.add(word);
    setSeenThisSeq(ns);

    const ni = idx + 1;
    if (ni >= wordSeq.length) {
      // End of round — merge all words into seenEver for next round
      const mergedSeen = new Set(seenEver);
      ns.forEach(w => mergedSeen.add(w));
      setSeenEver(mergedSeen);

      if (round >= ROUNDS_TOTAL) {
        setPhase("success");
        setTimeout(onComplete, 1500);
      } else {
        setPhase("roundComplete");
        setTimeout(() => {
          setLvlWipe(true);
          setTimeout(() => {
            initRound(round + 1);
            setTimeout(() => setLvlWipe(false), 100);
          }, 350);
        }, 1200);
      }
      return;
    }

    setTimeout(() => { setIdx(ni); setFeedback(null); }, 350);
  };

  const word = wordSeq[idx] || "";

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: "80vh", position: "relative", zIndex: 1 }}>
      <LevelTransition active={lvlWipe} />
      <div key={round} style={{ animation: "lvlSlideIn 0.4s ease-out", display: "flex", flexDirection: "column", alignItems: "center", width: "100%" }}>
      <HackHeader title="TRACEUR GPS" sub="Ce mot a-t-il deja ete affiche?" color={C.purple} step="1/4" onSkip={onComplete} description="Des mots s'affichent un par un. Determine si chaque mot a DEJA ETE VU dans cette session ou s'il est NOUVEAU. Les mots des rounds precedents restent en memoire!" example="Round 1: tu vois 'Firewall' → NOUVEAU. Round 2: 'Firewall' revient → DEJA VU." />

      {phase === "play" && (
        <>
          {/* Round indicator */}
          <div style={{ fontFamily: F.mono, fontSize: "11px", color: C.purple, marginBottom: "6px", letterSpacing: "2px" }}>
            ROUND {round}/{ROUNDS_TOTAL}
          </div>
          {/* Progress */}
          <div style={{ width: "100%", maxWidth: "380px", height: "3px", background: `${C.purple}20`, borderRadius: "2px", marginBottom: "8px" }}>
            <div style={{ width: `${((idx + 1) / WORDS_PER_ROUND) * 100}%`, height: "100%", background: C.purple, borderRadius: "2px", transition: "width 0.3s", boxShadow: `0 0 6px ${C.purple}` }} />
          </div>
          <div style={{ fontFamily: F.mono, fontSize: "11px", color: C.termDim, marginBottom: "6px" }}>
            {idx + 1}/{WORDS_PER_ROUND}
          </div>
          <div style={{ marginBottom: "20px" }}>
            <IntegrityBar current={MAX_ERR - errors} max={MAX_ERR} />
          </div>

          {/* Word display */}
          <div style={{
            padding: "35px 55px",
            background: `${C.purple}06`,
            border: `2px solid ${feedback === "ok" ? C.green : feedback === "no" ? C.red : C.purple}`,
            borderRadius: "10px",
            marginBottom: "22px",
            transition: "border-color 0.25s",
            boxShadow: `0 0 20px ${feedback === "ok" ? C.green : feedback === "no" ? C.red : C.purple}15`,
          }}>
            <div style={{
              fontFamily: F.mono,
              fontSize: "clamp(24px, 5vw, 34px)",
              fontWeight: "bold",
              color: C.white,
              textShadow: `0 0 12px ${C.purple}`,
              letterSpacing: "4px",
            }}>{word}</div>
          </div>

          {/* Buttons */}
          <div style={{ display: "flex", gap: "16px", maxWidth: "380px", width: "100%" }}>
            <button onClick={() => answer(false)} style={{
              flex: 1, padding: "14px",
              background: "transparent",
              border: `2px solid ${C.yellow}`,
              color: C.yellow,
              fontFamily: F.mono, fontSize: "15px", fontWeight: "bold",
              borderRadius: "6px", cursor: "pointer", transition: "all 0.2s",
              textShadow: `0 0 5px ${C.yellow}`,
            }}
            onMouseEnter={e => { e.currentTarget.style.background = `${C.yellow}12`; e.currentTarget.style.transform = "scale(1.04)"; }}
            onMouseLeave={e => { e.currentTarget.style.background = "transparent"; e.currentTarget.style.transform = "scale(1)"; }}
            >DEJA VU</button>
            <button onClick={() => answer(true)} style={{
              flex: 1, padding: "14px",
              background: "transparent",
              border: `2px solid ${C.cyan}`,
              color: C.cyan,
              fontFamily: F.mono, fontSize: "15px", fontWeight: "bold",
              borderRadius: "6px", cursor: "pointer", transition: "all 0.2s",
              textShadow: `0 0 5px ${C.cyan}`,
            }}
            onMouseEnter={e => { e.currentTarget.style.background = `${C.cyan}12`; e.currentTarget.style.transform = "scale(1.04)"; }}
            onMouseLeave={e => { e.currentTarget.style.background = "transparent"; e.currentTarget.style.transform = "scale(1)"; }}
            >NOUVEAU</button>
          </div>
        </>
      )}

      {phase === "success" && <StatusMsg ok text="TRACEUR GPS ACTIVE" />}
      {phase === "roundComplete" && <StatusMsg ok text={`ROUND ${round - 1} TERMINE`} />}
      </div>
      <ErrorOverlay visible={showError} onDone={() => { setShowError(false); setLvlWipe(false); init(); }} />
      <style>{`@keyframes lvlSlideIn { 0% { opacity:0; transform:translateY(-30px); } 100% { opacity:1; transform:translateY(0); } }`}</style>
    </div>
  );
}

// ════════════════════════════════════════════════
// SHARED UI COMPONENTS
// ════════════════════════════════════════════════
function IntegrityBar({ current, max }) {
  return (
    <div style={{ display: "inline-flex", alignItems: "center", gap: "6px", fontFamily: F.mono, fontSize: "11px" }}>
      <span style={{ color: C.termDim, letterSpacing: "1px", marginRight: "2px" }}>INTEGRITE</span>
      <span style={{ color: C.termDim }}>▐</span>
      {Array.from({ length: max }).map((_, i) => (
        <div key={i} style={{
          width: "18px", height: "18px",
          borderRadius: "3px",
          border: `2px solid ${i < current ? (current <= 1 ? C.red : C.terminal) : `${C.termDark}`}`,
          background: i < current ? (current <= 1 ? `${C.red}30` : `${C.terminal}25`) : "transparent",
          boxShadow: i < current ? `0 0 8px ${current <= 1 ? C.red : C.terminal}40` : "none",
          transition: "all 0.3s",
        }} />
      ))}
      <span style={{ color: C.termDim }}>▌</span>
      <span style={{ color: current <= 1 ? C.red : C.terminal, fontWeight: "bold", textShadow: `0 0 6px ${current <= 1 ? C.red : C.terminal}` }}>{current}/{max}</span>
    </div>
  );
}

function HackHeader({ title, sub, color, step, onSkip, description, example }) {
  const [showInfo, setShowInfo] = useState(false);
  return (
    <div style={{ marginBottom: "22px", textAlign: "center", position: "relative" }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: "10px" }}>
        <h2 style={{ fontFamily: F.mono, fontSize: "24px", color, textShadow: `0 0 15px ${color}`, margin: "0", letterSpacing: "3px" }}>
          {title}
        </h2>
        {(description || example) && (
          <div
            onMouseEnter={() => setShowInfo(true)}
            onMouseLeave={() => setShowInfo(false)}
            style={{ position: "relative", cursor: "pointer" }}
          >
            <div style={{
              width: "22px", height: "22px", borderRadius: "50%",
              border: `1.5px solid ${color}`, display: "flex", alignItems: "center",
              justifyContent: "center", fontFamily: F.mono, fontSize: "13px",
              fontWeight: "bold", color, transition: "all 0.2s",
              background: showInfo ? `${color}20` : "transparent",
              boxShadow: showInfo ? `0 0 10px ${color}40` : "none",
            }}>i</div>
            <div style={{
              position: "absolute", top: "32px", left: "50%", transform: "translateX(-50%)",
              width: "min(88vw, 360px)", zIndex: 100,
              background: "#111118", border: `1px solid ${color}40`,
              borderRadius: "8px", padding: showInfo ? "14px 16px" : "0 16px",
              maxHeight: showInfo ? "400px" : "0",
              opacity: showInfo ? 1 : 0, overflow: "hidden",
              transition: "max-height 0.25s ease-out, opacity 0.2s ease-out, padding 0.25s ease-out",
              boxShadow: `0 0 30px rgba(0,0,0,0.8), 0 0 10px ${color}15`,
              textAlign: "left", pointerEvents: showInfo ? "auto" : "none",
            }}>
              {description && (
                <div style={{ fontFamily: F.mono, fontSize: "11px", color: C.white, lineHeight: 1.7, marginBottom: example ? "10px" : "0" }}>
                  <span style={{ color, fontWeight: "bold", letterSpacing: "1px" }}>DESCRIPTION</span><br/>
                  {description}
                </div>
              )}
              {example && (
                <div style={{ fontFamily: F.mono, fontSize: "11px", color: C.termDim, lineHeight: 1.7, borderTop: `1px solid ${color}20`, paddingTop: "10px" }}>
                  <span style={{ color: C.yellow, fontWeight: "bold", letterSpacing: "1px" }}>EXEMPLE</span><br/>
                  {example}
                </div>
              )}
            </div>
          </div>
        )}
      </div>
      <div style={{ fontFamily: F.mono, fontSize: "12px", color: C.termDim, marginTop: "6px" }}>
        {sub}
      </div>
    </div>
  );
}

function ErrorOverlay({ visible, onDone }) {
  const [stage, setStage] = useState("none"); // none | glitch | cmd | rebooting
  const [typedErrLines, setTypedErrLines] = useState([]);
  const [currentErrTyping, setCurrentErrTyping] = useState(null);
  const [showRetry, setShowRetry] = useState(false);
  const errTypingRef = useRef(null);
  const errTermRef = useRef(null);

  const typeErrLines = useCallback((lines, onAllDone) => {
    const queue = [...lines];
    const typeNext = () => {
      if (queue.length === 0) { setCurrentErrTyping(null); if (onAllDone) onAllDone(); return; }
      const line = queue.shift();
      if (!line.t || !line.t.trim()) { setTypedErrLines(p => [...p, line]); setTimeout(typeNext, 12); return; }
      let ci = 0;
      const chars = line.t;
      setCurrentErrTyping({ ...line, text: "" });
      const tc = () => {
        if (ci >= chars.length) { setCurrentErrTyping(null); setTypedErrLines(p => [...p, line]); setTimeout(typeNext, 18); return; }
        ci = Math.min(ci + 1 + Math.floor(Math.random() * 2), chars.length);
        setCurrentErrTyping(prev => prev ? { ...prev, text: chars.substring(0, ci) } : null);
        errTypingRef.current = setTimeout(tc, 5 + Math.random() * 8);
      };
      tc();
    };
    typeNext();
  }, []);

  useEffect(() => {
    if (errTermRef.current) errTermRef.current.scrollTop = errTermRef.current.scrollHeight;
  }, [typedErrLines, currentErrTyping]);

  useEffect(() => {
    if (visible) {
      setStage("glitch");
      setTypedErrLines([]);
      setCurrentErrTyping(null);
      setShowRetry(false);
      setTimeout(() => {
        setStage("cmd");
        typeErrLines([
          { t: "ERREUR CRITIQUE — CONNEXION PERDUE", bright: true },
          { t: "[██████████████████] RESET COMPLETE", bright: false },
          { t: "", bright: false },
          { t: "PRET POUR NOUVELLE TENTATIVE", bright: true },
        ], () => setTimeout(() => setShowRetry(true), 100));
      }, 1900);
    } else {
      setStage("none");
    }
    return () => clearTimeout(errTypingRef.current);
  }, [visible]);

  const handleRestart = () => {
    setShowRetry(false);
    setStage("rebooting");
    const pid = Math.floor(Math.random() * 9000) + 1000;
    const port = Math.floor(Math.random() * 9000) + 30000;
    const ip = `${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)}.${Math.floor(Math.random()*255)}`;

    // 2 frozen status lines that stay visible during reboot
    setTypedErrLines(prev => [
      ...prev,
      { t: "", bright: false },
      { t: `[PID ${pid}]  Signal orbital .................. ACTIF`, bright: false, color: C.cyan },
      { t: `[TCP ${port}]  Tunnel AES-256-GCM ............... ACTIF`, bright: false, color: C.cyan },
      { t: "", bright: false },
    ]);

    const rebootLines = [
      { t: `root@lifeinvader:~# python3 reboot_module.py --force`, bright: false, color: C.terminal },
      { t: "", bright: false },
      { t: `from nexsat.core import OrbitalLink`, bright: false, color: "#ff8c42" },
      { t: `from crypto.cipher import AES_GCM`, bright: false, color: "#ff8c42" },
      { t: "", bright: false },
      { t: `link = OrbitalLink(pid=${pid})`, bright: false, color: "#ff6b6b" },
      { t: `link.reset_handshake()`, bright: false, color: "#ff6b6b" },
      { t: `resp = reconnect("${ip}", ${port})`, bright: false, color: "#ff6b6b" },
      { t: "", bright: false },
      { t: `>>> Handshake OK — latence: ${Math.floor(Math.random()*40)+12}ms`, bright: false, color: C.terminal },
      { t: `>>> Canal chiffre actif — AES-256-GCM`, bright: false, color: C.terminal },
      { t: "", bright: false },
      { t: "[■■■■■■■■■■] 100% — MODULE RECHARGE", bright: true },
      { t: "LANCEMENT...", bright: true },
    ];
    typeErrLines(rebootLines, () => {
      setTimeout(() => { setStage("none"); if (onDone) onDone(); }, 400);
    });
  };

  if (stage === "none") return null;

  if (stage === "glitch") return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 10000,
      display: "flex", alignItems: "center", justifyContent: "center",
      background: "rgba(6,6,11,0.92)",
      animation: "glitchShake 0.1s ease-in-out infinite",
    }}>
      <div style={{
        border: `2px solid ${C.red}`, borderRadius: "6px", padding: "24px 50px",
        background: "rgba(255,0,64,0.08)", boxShadow: `0 0 40px ${C.red}50, inset 0 0 25px ${C.red}15`,
      }}>
        <div style={{
          fontFamily: F.mono, fontSize: "clamp(28px, 6vw, 50px)", fontWeight: "bold",
          color: C.red, textShadow: `0 0 20px ${C.red}, 0 0 40px ${C.red}80`,
          letterSpacing: "6px", animation: "errorBlink 0.3s ease-in-out infinite",
        }}>ERREUR</div>
      </div>
      <div style={{ position: "absolute", inset: 0, background: "repeating-linear-gradient(0deg, transparent, transparent 3px, rgba(255,0,64,0.04) 3px, rgba(255,0,64,0.04) 6px)", pointerEvents: "none" }} />
      <style>{`
        @keyframes errorBlink { 0%{opacity:0} 50%{opacity:1} 100%{opacity:0} }
        @keyframes glitchShake { 0%{transform:translate(0,0)} 25%{transform:translate(-3px,2px)} 50%{transform:translate(3px,-2px)} 75%{transform:translate(-2px,-1px)} 100%{transform:translate(0,0)} }
      `}</style>
    </div>
  );

  const borderColor = stage === "rebooting" ? C.terminal : C.red;
  const titleBg = stage === "rebooting" ? "#101a14" : "#1a1018";
  const titleLabel = stage === "rebooting" ? "lifeinvader-breach — reboot" : "lifeinvader-breach — erreur";

  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 10000, display: "flex", alignItems: "center", justifyContent: "center", background: "rgba(6,6,11,0.92)" }}>
      <div style={{ width: "min(92vw, 520px)", background: "#0d0d12", border: `1px solid ${borderColor}60`, borderRadius: "8px", overflow: "hidden", boxShadow: `0 0 30px ${borderColor}25`, transition: "border-color 0.5s, box-shadow 0.5s" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "8px", padding: "7px 12px", background: titleBg, borderBottom: `1px solid ${borderColor}30`, transition: "background 0.5s" }}>
          <div style={{ width: 10, height: 10, borderRadius: "50%", background: C.red }} />
          <div style={{ width: 10, height: 10, borderRadius: "50%", background: C.yellow }} />
          <div style={{ width: 10, height: 10, borderRadius: "50%", background: C.terminal }} />
          <span style={{ fontFamily: F.mono, fontSize: "11px", color: `${borderColor}aa`, marginLeft: "8px", transition: "color 0.5s" }}>{titleLabel}</span>
        </div>
        <div ref={errTermRef} style={{ padding: "14px 16px", fontFamily: F.term, fontSize: "12px", lineHeight: 1.6, textAlign: "left", maxHeight: "380px", overflowY: "auto" }}>
          {typedErrLines.map((line, i) => (
            <div key={i} style={{
              color: line.color ? line.color : line.bright ? (stage === "rebooting" ? C.terminal : C.red) : C.termDim,
              textShadow: line.bright ? `0 0 8px ${stage === "rebooting" ? C.terminal : C.red}` : "none",
              whiteSpace: "pre-wrap",
            }}>{line.t || "\u00A0"}</div>
          ))}
          {currentErrTyping && (
            <div style={{
              color: currentErrTyping.color ? currentErrTyping.color : currentErrTyping.bright ? (stage === "rebooting" ? C.terminal : C.red) : C.termDim,
              textShadow: currentErrTyping.bright ? `0 0 8px ${stage === "rebooting" ? C.terminal : C.red}` : "none",
              whiteSpace: "pre-wrap",
            }}>
              {currentErrTyping.text}
              <span style={{ display: "inline-block", width: "8px", height: "14px", background: stage === "rebooting" ? C.terminal : C.red, verticalAlign: "middle", marginLeft: "1px" }} />
            </div>
          )}
        </div>
        {showRetry && (
          <div style={{ padding: "0 16px 14px", textAlign: "center" }}>
            <button onClick={handleRestart} style={{
              background: "transparent", border: `2px solid ${C.red}`, color: C.red,
              fontFamily: F.mono, fontSize: "14px", fontWeight: "bold",
              padding: "10px 40px", borderRadius: "4px", cursor: "pointer",
              letterSpacing: "3px", textShadow: `0 0 8px ${C.red}`,
              boxShadow: `0 0 15px ${C.red}20`,
              animation: "readyPulse2 1.5s ease-in-out infinite", transition: "all 0.2s",
            }}
            onMouseEnter={e => { e.currentTarget.style.background = `${C.red}15`; e.currentTarget.style.transform = "scale(1.05)"; }}
            onMouseLeave={e => { e.currentTarget.style.background = "transparent"; e.currentTarget.style.transform = "scale(1)"; }}
            >↻ RESTART</button>
          </div>
        )}
      </div>
      <style>{`@keyframes readyPulse2 { 0%,100%{box-shadow:0 0 15px ${C.red}20} 50%{box-shadow:0 0 30px ${C.red}40} }`}</style>
    </div>
  );
}

function StatusMsg({ ok, text }) {
  const col = ok ? C.green : C.red;
  return (
    <div style={{ fontFamily: F.mono, fontSize: "18px", color: col, marginTop: "22px", textShadow: `0 0 15px ${col}`, letterSpacing: "2px" }}>
      {ok ? "✓" : "✗"} {text}
    </div>
  );
}

function RetryBtn({ onClick }) {
  return (
    <button onClick={onClick} style={{
      marginTop: "16px",
      background: "transparent",
      border: `1px solid ${C.terminal}`,
      color: C.terminal,
      fontFamily: F.mono,
      fontSize: "14px",
      padding: "10px 30px",
      borderRadius: "4px",
      cursor: "pointer",
      letterSpacing: "2px",
      textShadow: `0 0 5px ${C.terminal}`,
    }}>
      REESSAYER
    </button>
  );
}

